solutions.cpp:
#include <numeric>

#include <iostream>

class Solution {
public:
    bool solve(long long N) {
        return N > 0 && (N & (N - 1)) == 0;
    }
};

int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);
    int T;
    if (!(std::cin >> T)) return 0;
    for (int i = 0; i < T; i++) {
        long long N;
        if (!(std::cin >> N)) return 0;
        Solution sol;
        bool ans = sol.solve(N);
        std::cout << (ans ? "YES" : "NO") << "\n";
    }
    return 0;
}
